INSERT INTO `questions` (`id`, `category`, `question`, `option_a`, `option_b`, `option_c`, `option_d`, `correct_answer`, `difficulty`, `created_at`) VALUES
(1, 'Hardware Troubleshooting', 'A workstation fails to power on and no LED indicators light up. What is the FIRST logical step?', 'Replace the motherboard', 'Check the power cable connection and test the wall socket', 'Reinstall the operating system', 'Replace all RAM modules', 1, 'easy', '2026-05-23 16:25:36'),
(2, 'Hardware Troubleshooting', 'A computer powers on but the monitor shows \"No Signal\". What should be checked FIRST?', 'Hard disk SATA cable', 'RAM module seating', 'Monitor cable connection and video output port', 'BIOS version', 2, 'easy', '2026-05-23 16:25:36'),
(3, 'Hardware Troubleshooting', 'Which Windows built-in tool is specifically designed to diagnose RAM errors?', 'chkdsk', 'Windows Memory Diagnostic', 'Device Manager', 'Disk Cleanup', 1, 'easy', '2026-05-23 16:25:36'),
(4, 'Hardware Troubleshooting', 'A workstation randomly shuts down during normal operation without any warning. The MOST LIKELY cause is:', 'Corrupted OS files', 'Insufficient disk space', 'CPU or system overheating triggering thermal protection', 'Outdated antivirus definitions', 2, 'medium', '2026-05-23 16:25:36'),
(5, 'Hardware Troubleshooting', 'A BSOD error message reads \"MEMORY_MANAGEMENT\". This primarily indicates:', 'Hard disk sector failure', 'Network adapter failure', 'RAM hardware fault or incompatibility', 'Printer driver corruption', 2, 'medium', '2026-05-23 16:25:36'),
(6, 'Hardware Troubleshooting', 'Three short beeps on an AMI BIOS system during POST usually indicate:', 'Successful boot completion', 'Video card error', 'RAM failure', 'Keyboard not detected', 2, 'medium', '2026-05-23 16:25:36'),
(7, 'Hardware Troubleshooting', 'A technician suspects a faulty PSU. Which instrument is used to measure output voltages?', 'Oscilloscope', 'Multimeter', 'Cable tester', 'Loopback plug', 1, 'medium', '2026-05-23 16:25:36'),
(8, 'Hardware Troubleshooting', 'A laptop screen shows flickering horizontal lines. The MOST LIKELY hardware cause is:', 'Defective RAM', 'Loose or damaged LCD flex cable', 'Hard disk failure', 'Overheating CPU', 1, 'hard', '2026-05-23 16:25:36'),
(9, 'Hardware Troubleshooting', 'A computer emits a continuous single long beep during startup. This typically indicates:', 'Successful POST', 'RAM is not detected or improperly seated', 'Hard disk failure', 'BIOS corruption', 1, 'hard', '2026-05-23 16:25:36'),
(10, 'Hardware Troubleshooting', 'The correct troubleshooting methodology sequence is:', 'Fix → Identify → Verify', 'Identify → Establish theory → Test → Implement fix → Verify → Document', 'Replace components at random until resolved', 'Restart → Format → Reinstall', 1, 'medium', '2026-05-23 16:25:36'),
(11, 'Hardware Troubleshooting', 'A USB device is unrecognized even after trying multiple ports on the same machine. What is the BEST next step?', 'Replace the motherboard', 'Test the USB device on another computer to isolate device vs. host fault', 'Format and reinstall the OS', 'Replace the USB cable only', 1, 'medium', '2026-05-23 16:25:36'),
(12, 'Hardware Troubleshooting', 'What is the primary function of thermal paste applied between a CPU and its heatsink?', 'Electrically insulate the processor', 'Fill microscopic surface imperfections to maximize heat transfer', 'Permanently bond the heatsink to the CPU', 'Prevent corrosion of the CPU lid', 1, 'medium', '2026-05-23 16:25:36'),
(13, 'Hardware Troubleshooting', 'A computer in a bank runs 24/7 and starts restarting every few hours. After ruling out OS issues, what component should be tested first?', 'Network card', 'UPS battery and power supply unit', 'Monitor', 'Keyboard', 1, 'hard', '2026-05-23 16:25:36'),
(14, 'Hardware Troubleshooting', 'After replacing a defective power supply, the computer still does not power on. What should be checked NEXT?', 'Replace the CPU', 'Verify the front-panel power button connector on the motherboard', 'Reinstall Windows', 'Replace the monitor', 1, 'hard', '2026-05-23 16:25:36'),
(15, 'Hardware Troubleshooting', 'A grinding or clicking noise from a PC typically indicates a failing:', 'CPU fan bearing', 'RAM module', 'HDD with mechanical damage', 'Graphics card fan', 0, 'easy', '2026-05-23 16:25:36'),
(16, 'Hardware Troubleshooting', 'ESD stands for:', 'Electronic System Diagnostics', 'Electrostatic Discharge — static electricity that can destroy components', 'External Storage Device', 'Encrypted System Data', 1, 'easy', '2026-05-23 16:25:36'),
(17, 'Hardware Troubleshooting', 'Before opening a PC case to replace internal components, a technician should FIRST:', 'Update drivers', 'Disconnect from power and use an anti-static wrist strap', 'Run a virus scan', 'Back up all user files', 1, 'easy', '2026-05-23 16:25:36'),
(18, 'Hardware Troubleshooting', 'A computer POST completes but Windows fails to load, showing \"Operating System Not Found\". This suggests:', 'RAM failure', 'The hard disk is not detected or the MBR/boot record is corrupted', 'Monitor failure', 'CPU overheating', 1, 'medium', '2026-05-23 16:25:36'),
(19, 'Hardware Troubleshooting', 'Which of the following BEST describes a \"loopback test\" for a network card?', 'Testing cable continuity with a cable tester', 'Sending data back to itself to verify the NIC transmits and receives correctly', 'Checking IP address assignment', 'Testing DNS resolution', 1, 'hard', '2026-05-23 16:25:36'),
(20, 'Hardware Troubleshooting', 'A keyboard types wrong characters (e.g., pressing \"q\" produces \"a\"). The MOST LIKELY cause is:', 'Hardware keyboard failure', 'Incorrect keyboard language/input layout set in OS', 'Virus infection', 'BIOS settings corrupted', 1, 'easy', '2026-05-23 16:25:36'),
(21, 'BIOS & CMOS', 'What does BIOS stand for?', 'Binary Integrated Output System', 'Basic Input/Output System', 'Boot Initialization Operating Software', 'Binary Input/Output Software', 1, 'easy', '2026-05-23 16:25:36'),
(22, 'BIOS & CMOS', 'What is the primary purpose of the CMOS battery on the motherboard?', 'Power the CPU during startup', 'Maintain system date/time and BIOS settings when power is removed', 'Charge the laptop battery', 'Power the hard disk during boot', 1, 'easy', '2026-05-23 16:25:36'),
(23, 'BIOS & CMOS', 'Which symptom MOST clearly indicates a dead CMOS battery?', 'Computer fails to POST', 'System clock resets to default date/time every time computer is powered off', 'Internet connection drops frequently', 'Monitor shows no display', 1, 'easy', '2026-05-23 16:25:36'),
(24, 'BIOS & CMOS', 'UEFI is best described as:', 'A type of RAM', 'A replacement/successor to traditional BIOS with a graphical interface and larger disk support', 'An operating system', 'A type of network protocol', 1, 'medium', '2026-05-23 16:25:36'),
(25, 'BIOS & CMOS', 'In BIOS/UEFI, what does \"Boot Order\" or \"Boot Priority\" control?', 'Fan speed control', 'The sequence of devices the computer attempts to load the OS from', 'Screen brightness during POST', 'RAM speed settings', 1, 'easy', '2026-05-23 16:25:36'),
(26, 'BIOS & CMOS', 'After replacing the CMOS battery, a technician must:', 'Reinstall the OS', 'Re-enter the correct date/time and verify BIOS settings', 'Run chkdsk', 'Replace the RAM', 1, 'easy', '2026-05-23 16:25:36'),
(27, 'BIOS & CMOS', 'A \"CMOS Checksum Error\" message during startup indicates:', 'OS corruption', 'BIOS settings have been lost, typically due to a dead CMOS battery', 'Hard disk failure', 'RAM incompatibility', 1, 'medium', '2026-05-23 16:25:36'),
(28, 'BIOS & CMOS', 'Which key combination or key is most commonly used to enter BIOS setup on modern systems?', 'Ctrl+Alt+Delete', 'Delete, F2, or F10 during POST (varies by manufacturer)', 'Windows key + R', 'Alt+F4', 1, 'easy', '2026-05-23 16:25:36'),
(29, 'BIOS & CMOS', 'Enabling \"Secure Boot\" in UEFI primarily prevents:', 'Unauthorized users from accessing BIOS', 'Unsigned or malicious bootloaders and OS from loading', 'Overclocking of components', 'Automatic updates', 1, 'hard', '2026-05-23 16:25:36'),
(30, 'BIOS & CMOS', 'What is the function of the BIOS POST routine?', 'Format the hard disk', 'Test and initialize all hardware components before loading the OS', 'Install device drivers', 'Authenticate the user', 1, 'easy', '2026-05-23 16:25:36'),
(31, 'BIOS & CMOS', 'A \"162 — System Options Not Set\" POST error code indicates:', 'Keyboard failure', 'CMOS data lost — configuration change detected', 'Video card not found', 'RAM slot failure', 1, 'hard', '2026-05-23 16:25:36'),
(32, 'BIOS & CMOS', 'Which BIOS setting would a technician enable to allow a PC to boot from a USB flash drive?', 'Enable Hyperthreading', 'Set USB as first boot device in boot priority', 'Enable RAID mode', 'Disable Secure Boot only', 1, 'medium', '2026-05-23 16:25:36'),
(33, 'BIOS & CMOS', 'The difference between MBR and GPT partition schemes relates to:', 'File system type only', 'Disk partitioning standard — GPT supports disks over 2TB and more than 4 primary partitions', 'RAM addressing', 'Network boot configuration', 1, 'hard', '2026-05-23 16:25:36'),
(34, 'BIOS & CMOS', 'Flashing the BIOS means:', 'Restarting the computer quickly', 'Updating the firmware stored in the BIOS chip', 'Clearing BIOS password', 'Formatting the boot partition', 1, 'medium', '2026-05-23 16:25:36'),
(35, 'BIOS & CMOS', 'TPM in modern BIOS/UEFI settings stands for:', 'Total Power Management', 'Trusted Platform Module — a security chip used for encryption and secure boot', 'Terminal Protocol Module', 'Transfer Protocol Memory', 1, 'hard', '2026-05-23 16:25:36'),
(36, 'RAM & Memory', 'RAM stands for:', 'Read Access Memory', 'Random Access Memory', 'Rapid Application Module', 'Read-only Array Module', 1, 'easy', '2026-05-23 16:25:36'),
(37, 'RAM & Memory', 'The primary role of RAM in a computer system is:', 'Permanently store the operating system', 'Temporarily hold data and instructions currently being processed by the CPU', 'Store the BIOS firmware', 'Control network communication', 1, 'easy', '2026-05-23 16:25:36'),
(38, 'RAM & Memory', 'What is the minimum recommended RAM for running Windows 11 smoothly in a corporate environment?', '512 MB', '2 GB', '8 GB or more', '128 MB', 2, 'medium', '2026-05-23 16:25:36'),
(39, 'RAM & Memory', 'DDR5 RAM offers what primary advantage over DDR4?', 'Lower price', 'Higher bandwidth and improved power efficiency', 'Compatible with DDR4 slots', 'Larger physical size', 1, 'hard', '2026-05-23 16:25:36'),
(40, 'RAM & Memory', 'Dual-channel memory configuration requires:', 'Two identical RAM modules installed in the correct paired slots', 'Any two different RAM sticks', 'Four RAM sticks only', 'A special motherboard setting only', 0, 'medium', '2026-05-23 16:25:36'),
(41, 'RAM & Memory', 'A technician installs a new RAM module and the computer beeps continuously. The MOST LIKELY cause is:', 'Incorrect OS version', 'RAM is not fully seated in the slot or is incompatible', 'Monitor cable loose', 'PSU is underpowered', 1, 'medium', '2026-05-23 16:25:36'),
