(49, 'Storage & RAID', 'Which RAID level requires a minimum of 3 disks and provides both performance and fault tolerance using parity?', 'RAID 0', 'RAID 1', 'RAID 5', 'RAID 10', 2, 'medium', '2026-05-23 16:25:36'),
