(56, 'Storage & RAID', 'An S.M.A.R.T. warning from a hard disk means:', 'Disk is performing optimally', 'The disk is reporting early signs of failure — back up data immediately', 'RAM needs upgrading', 'BIOS needs updating', 1, 'hard', '2026-05-23 16:25:36'),
(57, 'Storage & RAID', 'What is the purpose of a hot spare in a RAID array?', 'Acts as an extra active disk for speed', 'A standby disk that automatically replaces a failed drive without manual intervention', 'Extra storage only', 'A backup of the RAID controller', 1, 'hard', '2026-05-23 16:25:36'),
(58, 'Storage & RAID', 'NVMe (Non-Volatile Memory Express) is a protocol designed for:', 'Connecting monitors', 'High-speed SSDs using the PCIe interface', 'Network storage', 'USB drives', 1, 'hard', '2026-05-23 16:25:36'),
