(81, 'Networking', 'VPN stands for and provides:', 'Virtual Private Node — faster routing', 'Virtual Private Network — encrypted tunnel over public internet for secure remote access', 'Virtual Protocol Network — LAN extension', 'Verified Protected Network — firewall service', 1, 'medium', '2026-05-23 16:25:36'),
(82, 'Networking', 'VLAN technology allows:', 'Wireless devices to connect', 'Logical segmentation of a physical network into separate broadcast domains', 'Automatic IP assignment', 'Remote desktop access', 1, 'hard', '2026-05-23 16:25:36'),
