(88, 'Networking', 'What is the well-known port number for HTTPS?', '80', '21', '443', '22', 2, 'medium', '2026-05-23 16:25:36'),
(89, 'Networking', 'A network adapter shows \"Limited or No Connectivity\" in Windows. FIRST troubleshooting step?', 'Replace the router', 'Release and renew IP address using ipconfig /release then ipconfig /renew', 'Replace the network cable', 'Call ISP immediately', 1, 'medium', '2026-05-23 16:25:36'),
